import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6257_矽格/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md","filePath":"審計報告庫/財務審計/6257_矽格/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md"}'),o={name:"審計報告庫/財務審計/6257_矽格/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md"};function l(n,a,s,d,h,c){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="f16-大股東成本與籌碼結構審計-投資研究員-審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-投資研究員-審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：400張以上大戶合計持股51.14%，董監事持股僅4.82%且質押率0%，屬「低持股零槓桿」型態，內部人利益綁定薄弱，但無斷頭風險。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2026年4月最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：400張以上大戶51.14%，千張以上43.83%；外資持股27.39%（自2024/03峰值30.54%減持315bps）；董監持股4.82%，質押0%；PER 28.77倍、PBR 3.90倍。</li><li><strong>診斷見解</strong>：籌碼呈「外資主導+大戶鎖定」雙層結構。外資自30.54%降至27.39%，減持7.8%屬獲利了結非恐慌拋售。董監4.82%為極低水準，反映內部人投入意願不足。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_400張與1000張大戶持股" tabindex="-1">400張與1000張大戶持股 <a class="header-anchor" href="#_400張與1000張大戶持股" aria-label="Permalink to &quot;400張與1000張大戶持股&quot;">​</a></h3><ul><li><strong>核心重點</strong>：1,000,001股以上（≈400張）64戶佔42.78%~43.83%；400張以上合計51.14%。散戶（1-999張）34,722人僅佔0.31%。</li><li><strong>深度見解</strong>：超級大戶平均持有3,070張，典型機構特徵。散戶對股價影響力微乎其微，籌碼集中度高。</li></ul><h3 id="董監持股與質押" tabindex="-1">董監持股與質押 <a class="header-anchor" href="#董監持股與質押" aria-label="Permalink to &quot;董監持股與質押&quot;">​</a></h3><ul><li><strong>核心重點</strong>：董事長黃興陽7,616張（1.57%），全體董監4.82%，質押0%。近期僅林瑞德增持32張（113/06）。</li><li><strong>深度見解</strong>：4.82%遠低於S等級門檻25%，但零質押完全消除了斷頭風險。無內部人大量加碼的正面信號。</li></ul><h3 id="外資成本與趨勢" tabindex="-1">外資成本與趨勢 <a class="header-anchor" href="#外資成本與趨勢" aria-label="Permalink to &quot;外資成本與趨勢&quot;">​</a></h3><ul><li><strong>核心重點</strong>：外資2024/01持股26.59%→2024/03升至30.54%→2026/04降至27.39%。2024年1-3月淨買超1,225萬股，3月後淨賣超1,118萬股。</li><li><strong>深度見解</strong>：外資建倉成本約26~30元，當前股價約72元，帳面獲利140%~177%，獲利了結壓力隨估值升高而放大。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：外資持股跌破25%後，配合PER 28.77倍高估值，1,000張以上43.78%大戶若同步減持10%，將產生4.4%流通股拋壓。</li><li><strong>空頭風險二</strong>：董監僅4.82%且無加碼，2025年4月營收YoY僅+5.5%，若成長率轉負，內部人買盤支撐完全缺失，股價下檔無緩衝。</li><li><strong>空頭風險三</strong>：當前PER 29倍處歷史高檔，若大額賣壓湊巧遇上流動性低谷，可能觸發快速修正。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind holding</strong>: OK - 2026/04/29外資持股27.39%</li><li><strong>FinMind spread</strong>: OK - 2024/01持股分級數據，400張以上51.14%</li><li><strong>FinMind per</strong>: OK - 2026/04/29 PER=28.77, PBR=3.90</li><li><strong>FinMind dividend</strong>: OK - 111年4.20元, 112年2.60元, 113年2.53元</li><li><strong>年報</strong>: OK - 實收資本額48.39億, 已發行483,912,325股</li><li><strong>質押資料</strong>: 2026年3月公開資訊觀測站確認質押0%</li><li><strong>關鍵核對碼</strong>: <code>2026-04-29 ForeignInvestmentSharesRatio=27.39% NumberOfSharesIssued=483,912,325</code> / <code>2024-01-26 more than 1,000,001=64戶 percent=43.83%</code></li></ul>',19)])])}const u=t(o,[["render",l]]);export{g as __pageData,u as default};
